// involves_user_id widens the assignee filter to surface issues where the user
// is *indirectly* the assignee — via an owned multica_agent or a multica_squad they belong to /
// lead / have an multica_agent inside. The semantics intentionally exclude direct
// multica_member assignment (`assignee_type='member' AND assignee_id=involves_user_id`)
// because that is already the meaning of the `assignee_id` filter (tab 1
// "Assigned to me"), and the two filters must produce disjoint result sets.
func (q *Queries) ListIssues(ctx context.Context, arg ListIssuesParams) ([]ListIssuesRow, error) {
	rows, err := q.db.Query(ctx, listIssues,
		arg.WorkspaceID,
		arg.Limit,
		arg.Offset,
		arg.ExcludeWorkflowOrigin,
		arg.Status,
		arg.Priority,
		arg.AssigneeID,
		arg.AssigneeIds,
		arg.CreatorID,
		arg.ProjectID,
		arg.Scheduled,
		arg.MetadataFilter,
		arg.InvolvesUserID,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []ListIssuesRow{}
	for rows.Next() {
		var i ListIssuesRow
		if err := rows.Scan(
			&i.ID,
			&i.WorkspaceID,
			&i.Title,
			&i.Description,
			&i.Status,
			&i.Priority,
			&i.AssigneeType,
			&i.AssigneeID,
			&i.CreatorType,
			&i.CreatorID,
			&i.ParentIssueID,
			&i.Position,
			&i.StartDate,
			&i.DueDate,
			&i.CreatedAt,
			&i.UpdatedAt,
			&i.Number,
			&i.ProjectID,
			&i.WorkflowID,
			&i.WorkflowRunID,
			&i.StageID,
			&i.Metadata,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

